mapper.update:
update synlte.public_data_info set zyzt = #{status}, GXSJ = sysdate where upper(sjxjbm) in (
select #{item} from dual
)

update synlte.object set objectstate = #{status} , updatetime = sysdate where upper(tableid) in (
select #{item} from dual
)

update synlte.FIELD_RESOURCE_INFO set SFCXTJ = #{query}, SFDYTJ=#{subscribe}, ZDFL =#{fieldClassId}, ZDMGDFLDM=#{sensitivityLevel}, GXSJ=sysdate where upper(tableid) = upper(#{tableId}) and upper(sjxywmc) in (
select #{item} from dual
)

update synlte.objectfield set ISQUERY = #{query}, COLUMNNAME_STATE=#{columnNameState}
where upper(objectId) = upper(#{objectId})
and  upper(COLUMNNAME)
in (

    select #{item} from dual

)

update synlte.SYNLTEFIELD set field_class = #{fieldClassId} where upper(columnname) in (

    select #{item} from dual

)
